using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF9 breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Preserve old name so existing documents and raw SQL (c.Discriminator) keep working.
            b.HasDiscriminator<string>("Discriminator");

            // EF9 breaking change: JSON "id" no longer includes the discriminator prefix.
            // Existing docs have id = "Product|123"; this restores that format.
            b.HasDiscriminatorInJsonId();

            // EF9 breaking change: key property is now mapped directly to JSON "id".
            // Existing docs store the key separately (e.g. "Id": 123 alongside "id": "Product|123").
            // This keeps the prior shadow-property approach so that layout is preserved.
            b.HasShadowId();

            // EF9 breaking change: HasIndex now throws (Cosmos indexes all properties by default).
            // Removed the previous HasIndex(p => p.Sku) call.
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

